package com.treeeducation.ioas.task; import io.swagger.v3.oas.annotations.media.Schema;import jakarta.validation.constraints.NotNull; /** Task DTOs. */ public final class TaskDtos{private TaskDtos(){} @Schema(description="更新任务请求") public record UpdateRequest(@NotNull TaskStatus status,Long assigneeId){} @Schema(description="任务响应") public record Response(Long id,TaskType type,TaskStatus status,String title,Long packageId,Long assetFileId,Long leadId,Long assigneeId){} public static Response of(Task t){return new Response(t.getId(),t.getType(),t.getStatus(),t.getTitle(),t.getPackageId(),t.getAssetFileId(),t.getLeadId(),t.getAssigneeId());}}
